const q = msg.req.query;

// Validar parámetros mínimos
if (!q.staging_id || !q.mysql_query) {
    msg.statusCode = 400;
    msg.payload = JSON.stringify({
        ok: false,
        error: 'Faltan parámetros: staging_id y mysql_query son requeridos',
        recibido: Object.keys(q)
    });
    msg.headers = { 'Content-Type': 'application/json' };
    node.warn('Recepción inválida: ' + JSON.stringify(q));
    return [null, msg];
}

// El mysql_query viene URL-encoded, Node-RED ya lo decodifica en req.query
const sqlQuery = q.mysql_query;

// Pasar query al nodo MySQL (msg.topic = SQL a ejecutar)
msg.topic = sqlQuery;
msg.payload = {};

// Guardar datos para el log y la respuesta
msg._factura = {
    staging_id:    q.staging_id,
    cuit:          q.cuit          || '',
    razon_social:  q.razon_social  || '',
    nro_documento: q.nro_documento || '',
    letra:         q.letra         || '',
    fecha_emision: q.fecha_emision || '',
    total:         q.total         || '',
    confianza:     q.confianza_parseo || ''
};

node.log('Registrando factura: ' + q.staging_id + ' | ' + q.razon_social);
return [msg, null];

const f = msg._factura || {};
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({
    ok: true,
    staging_id:   f.staging_id,
    razon_social: f.razon_social,
    nro_documento: f.nro_documento,
    total:        f.total,
    mensaje:      'Factura registrada en staging_facturas'
});
node.log('OK: ' + f.staging_id);
return msg;

const f = msg._factura || {};
node.error('Error MySQL para staging_id ' + f.staging_id + ': ' + msg.error.message);
msg.statusCode = 500;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({
    ok: false,
    staging_id: f.staging_id,
    error: msg.error.message || 'Error desconocido en MySQL'
});
return msg;
